const parseDependencies = (
	jsonSchema: JsonSchema.Object,
	parse: ParseJsonSchema
): Predicate.Schema[] => {
	const dependentRequired = jsonSchema.dependentRequired ?? jsonSchema.dependencies
	const dependentSchemas = jsonSchema.dependentSchemas
	const predicates: Predicate.Schema[] = []
	if (dependentRequired) {
		predicates.push(function jsonSchemaDependentRequiredValidator(data, ctx) {
			for (const [trigger, required] of Object.entries(dependentRequired)) {
				if (!(trigger in data)) continue
				for (const key of required)
					if (!(key in data))
						return ctx.reject({ expected: `a '${key}' property when '${trigger}' is present`, actual: "missing" })
			}
			return true
		})
	}
	if (dependentSchemas) {
		for (const [trigger, schema] of Object.entries(dependentSchemas)) {
			const validator = parse(schema)
			predicates.push(function jsonSchemaDependentSchemaValidator(data, ctx) {
				return !(trigger in data) || validator.allows(data) || ctx.reject({
					expected: validator.description,
					actual: printable(data)
				})
			})
		}
	}
	return predicates
}

